from collections import Counter

class Solution(object):
    def minOperations(self, nums):
        ptr = 0
        ops = 0
        while True:
            remaining = nums[ptr:]
            if not remaining:
                break
            if len(Counter(remaining)) == len(remaining):
                break
            ptr += 3
            ops += 1
        return ops
